// ── Merge CSV businesses into BUSINESSES object ───────────────────
// This adds all scanned businesses to their categories
// Hand-written businesses above take priority (appear first)
(function mergeCsvBusinesses() {
  for (const [cat, bizList] of Object.entries(BUSINESSES_FROM_CSV)) {
    if (!BUSINESSES[cat]) {
      BUSINESSES[cat] = [];
    }
    // Only add if not already in hand-written list (avoid dupes by name)
    const existingNames = new Set(BUSINESSES[cat].map(b => b.name.toLowerCase()));
    for (const biz of bizList) {
      if (!existingNames.has(biz.name.toLowerCase())) {
        BUSINESSES[cat].push(biz);
      }
    }
  }
})();
